UPDATE friend_relation
group_name = #{groupName}, remark = #{remark}, is_starred = #{isStarred}, is_blocked = #{isBlocked}, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT fr.* FROM friend_relation fr
WHERE fr.user_id = #{userId}
AND fr.group_name = #{groupName}
AND fr.is_starred = #{isStarred}

    AND EXISTS (
    SELECT 1 FROM user u
    WHERE u.id = fr.friend_id
    AND (u.nickname LIKE CONCAT('%', #{keyword}, '%') OR fr.remark LIKE CONCAT('%', #{keyword}, '%'))
    )

ORDER BY

    fr.interaction_count DESC, 
    fr.become_friend_time DESC, 

fr.create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM friend_relation fr
WHERE fr.user_id = #{userId}
AND fr.group_name = #{groupName}
AND fr.is_starred = #{isStarred}

